INSERT INTO public.industry_issue (full_name, first_name, last_name, headline, linkedin_url, public_identifier, raw_data) VALUES
('Rahul G.', 'Rahul', 'G.', 'Hotel General Manager | Driving Exceptional Guest Experiences and Profitability', 'https://www.linkedin.com/in/rahulgupta9900', 'rahulgupta9900', $${"about": "Performance-focused General Manager currently leading a premier 4-star hotel in Pattaya, Thailand. I specialize in transforming market challenges into financial milestones. Over the past three years, I have spearheaded a comprehensive recovery and growth strategy that resulted in consecutive annual revenue increments of 35%, 25.18%, and 12.13%. My leadership style blends data-driven revenue management with a guest-centric approach, ensuring that fiscal growth is matched by exceptional service standards.\n\nYield Maximization: Outperformed the Pattaya 4-star comp-set by maintaining a high RevPAR (Revenue Per Available Room) index, even during seasonal fluctuations.\n\nCost Control & GOP Optimization: Implemented strict labor-management and energy-saving protocols that ensured revenue growth flowed directly to the bottom line, protecting Gross Operating Profit (GOP) margins during periods of high inflation.\n\nGuest Loyalty & Reputation: Elevated the property’s ranking on TripAdvisor and OTA platforms, maintaining a high Guest Satisfaction Score which served as the foundation for the 12.13% growth in repeat business for the 2024–2025 period.", "addressCountryOnly": "Thailand", "addressWithCountry": "Greater Pattaya Area, Thailand", "addressWithoutCountry": "Greater Pattaya Area", "companyName": "Mind Resort Pattaya", "connections": "13036", "creatorWebsite/0/category": "OTHER", "creatorWebsite/0/url": "http://www.compasshospitality.com/", "creatorWebsite/1/category": "OTHER", "creatorWebsite/1/url": "http://www.citinlofthuahin.com/", "currentJobDuration": "7 yrs 1 mo", "currentJobDurationInYrs": "7.08", "educations/0/description": "Outstanding Achievement\nMr. Rahul,  were selected to join UMAP (University Mobility in Asia and the Pacific) Thailand Scholarship 2007.", "educations/0/period/endedOn/month": "0", "educations/0/period/endedOn/year": "2008", "educations/0/period/startedOn/month": "0", "educations/0/period/startedOn/year": "2006", "educations/0/subtitle": "MBA Degree, Hotel and International Business Management", "educations/0/title": "Master of Business Administration (MBA) Specialization: Hotel and Business Management Siam  University, Thailand | 2006 – 2008", "educations/1/description": "Core Focus: Comprehensive training in Front Office, F&B Operations, Housekeeping Management, \nand Professional Communication Skills.", "educations/1/period/endedOn/month": "0", "educations/1/period/endedOn/year": "2006", "educations/1/period/startedOn/month": "0", "educations/1/period/startedOn/year": "2005", "educations/1/subtitle": "Certificate, Hotel Management", "educations/1/title": "Diploma in Hotel Management Regional Institute of Management | 2005 – 2006", "educations/2/description": "Core Focus: Macro/Micro Economics, Social Dynamics, and Statistical Analysis.", "educations/2/period/endedOn/month": "0", "educations/2/period/endedOn/year": "2006", "educations/2/period/startedOn/month": "0", "educations/2/period/startedOn/year": "2003", "educations/2/subtitle": "Bachelor Degree, Political Science and Economics", "educations/2/title": "Bachelor of Arts (B.A.) Major: Economics and Social Science Shimla Government University, India | 2003 – 2006", "experiences/0/companyName": "Mind Resort Pattaya", "experiences/0/employmentType": "Full-time", "experiences/0/jobDescription": "As General Manager, I oversee all aspects of resort operations, leading a cross-functional team of 80+ employees to maintain the highest standards of service and safety.\n\nKey Achievements:\n\nFinancial Growth: Drove RevPAR and ADR growth by 8% year-over-year by implementing dynamic revenue management strategies focused on high-yield leisure and group segments.\n\nReputation Management: Successfully elevated Guest Satisfaction Scores (GSS) and online reputation (TripAdvisor/Google) from 2.2 to 3.7, securing a top-tier ranking in the regional market.\n\nOperational Efficiency: Cut annual operational expenses by 9% through the strategic negotiation of favorable contracts with key vendors (F&B, linen, and grounds).\n\nDigital Transformation: Streamlined guest services by implementing AI technology platforms, reducing check-in/out times by 8% and significantly boosting staff productivity.\n\nLeadership & Retention: Mentored a diverse team of 80+ staff, resulting in a measurable increase in employee retention over an 18-month period.\n\nCompliance & Safety: Maintained 100% compliance with international hotel standards, ensuring zero health or safety violations across the property.", "experiences/0/jobLocation": "Pattaya, Thailand, South East Asia", "experiences/0/jobStartedOn": "4-2019", "experiences/0/jobStillWorking": "true", "experiences/0/title": "\"General Manager at Mind Resort Pattaya | Hospitality Leader | Revenue & Guest Experience Expert\"", "experiences/1/companyName": "Mind Resort Pattaya", "experiences/1/employmentType": "Full-time", "experiences/1/jobStartedOn": "4-2019", "experiences/1/jobStillWorking": "true", "experiences/1/title": "General Manager", "experiences/2/companyName": "Pattaya Loft Hotel (Earlier Citin Loft Managed by COMPASS HOSPITALITY)", "experiences/2/employmentType": "Full-time", "experiences/2/jobDescription": "General Manager | August 2015 – April 2019\n\nChange Management: Successfully led the operational transition and rebranding from Citin Loft (under Compass Hospitality) to Pattaya Loft Hotel, ensuring seamless service continuity and team stability.\n\nRevenue Growth: Identified and captured new market opportunities within the Pattaya sector through innovative sales and marketing strategies.\n\nBudgetary Oversight: Developed and managed annual operating budgets, consistently meeting financial targets through rigorous expense monitoring.\n\nOperational Efficiency: Implemented cost-effective initiatives to enhance workflow without compromising the high-quality service standards of the property.\n\nLeadership: Provided strategic guidance to department heads, fostering a culture of professional growth and personalized guest service.", "experiences/2/jobEndedOn": "4-2019", "experiences/2/jobLocation": "Pattaya, Chonburi, Thailand", "experiences/2/jobStartedOn": "8-2015", "experiences/2/jobStillWorking": "false", "experiences/2/title": "General Manager | August 2015 – April 2019", "experiences/3/companyName": "Royal Orchid Resort Pattaya Full-time | Jun 2014 – Aug 2015 (1 yr 3 mos) Pattaya, Thailand | On-site", "experiences/3/employmentType": "Full-time", "experiences/3/jobDescription": "Managed a 120-room resort with a strategic focus on high-volume international markets. I held dual responsibility for full resort operations and leading the Sales & Marketing division to diversify the guest portfolio and maximize occupancy.\n\nKey Achievements:\n\nMarket Expansion & Sales: Significantly increased total revenue by securing new contracts with Travel Agents (TAs), OTAs, B2B partners, and corporate clients, specifically targeting the Chinese and Indian markets.\n\nOnline Reputation Management: Proactively managed online reviews and feedback platforms, leading to improved digital visibility and guest trust.\n\nFull-Cycle Operations: Oversaw all resort departments, ensuring a seamless guest journey from arrival through check-out, while maintaining rigorous product and service quality standards.\n\nQuality Control: Conducted ongoing property evaluations and investigated service gaps to ensure the resort met and exceeded guest expectations.\n\nFinancial Performance: Managed profit margins through strategic cost-control measures, ensuring profitability remained high without sacrificing guest or employee satisfaction.\n\nData-Driven Improvement: Regularly reviewed guest comment cards and satisfaction surveys to implement real-time service recovery and operational upgrades.", "experiences/3/jobEndedOn": "8-2015", "experiences/3/jobLocation": "South East Asia Thailand", "experiences/3/jobStartedOn": "6-2014", "experiences/3/jobStillWorking": "false", "experiences/3/title": "Resort Manager", "experiences/4/companyName": "Suncity Hotel Full-time | May 2012 – Jun 2014 (2 yrs 2 mos) Pattaya, Chonburi, Thailand | On-site", "experiences/4/employmentType": "Full-time", "experiences/4/jobDescription": "As Resident Manager, I exercised full operational control over the property, overseeing all departments to ensure seamless day-to-day functions. I balanced strategic business development with hands-on management to maintain high standards of service and profitability.\n\nKey Responsibilities & Achievements:\n\nOperational Supervision: Supervised staff and work quality at all levels, fostering a disciplined and efficient work environment across all hotel departments.\n\nFinancial & Budgetary Management: Managed comprehensive budgets and financial reporting, ensuring all activities aligned with the property’s fiscal goals.\n\nStrategic Marketing: Developed and executed targeted marketing strategies to drive occupancy and increase brand awareness within the competitive Pattaya market.\n\nFacility Maintenance: Directed all maintenance and engineering projects, ensuring the property remained in peak condition and addressing facility issues proactively.\n\nHealth & Safety Leadership: Enforced strict health and safety standards, ensuring the property was fully compliant with local regulations and industry best practices.\n\nStakeholder & Customer Relations: Acted as the primary point of contact for external partners and high-value guests, resolving complex customer issues and building long-term relationships.", "experiences/4/jobEndedOn": "6-2014", "experiences/4/jobLocation": "Pattaya, Chon Buri, Thailand", "experiences/4/jobStartedOn": "5-2012", "experiences/4/jobStillWorking": "false", "experiences/4/title": "Resident Manager", "experiences/5/companyName": "Loft Hotel Hua Hin & Royal Express Inn (Managed by Compass Hospitality) | Aug 2009 – Jun 2012", "experiences/5/employmentType": "Full-time", "experiences/5/jobDescription": "Spearheaded the day-to-day management of two distinct properties, ensuring operational excellence across all departments including Front Office, F&B, and Housekeeping. I focused on building a culture of service leadership while maintaining strict commercial accountability.\n\nKey Responsibilities & Achievements:\n\nMulti-Property Leadership: Managed operations for both Loft Hotel and Royal Express Inn, aligning both properties with Compass Hospitality’s Standard Operating Procedures (SOPs).\n\nFinancial & Revenue Management: Analyzed sales figures to devise effective marketing and revenue strategies, consistently hitting sales targets and managing expenditures to maximize GOP.\n\nTeam Development: Directly responsible for interviewing, hiring, and mentoring junior staff; led by example to inspire a high-performing team focused on guest retention.\n\nProduct Innovation: Implemented attractive service packages tailored to specific target groups, successfully executing pre-agreed marketing plans and budgets.\n\nGuest Relations & Quality Control: Monitored staff presentation and performance to ensure 100% compliance with hotel rules, while personally troubleshooting complex guest issues to ensure high satisfaction.\n\nOperational Security: Managed all aspects of property security and maintenance to ensure a safe and seamless environment for international and local guests.", "experiences/5/jobEndedOn": "6-2012", "experiences/5/jobLocation": "Thailand", "experiences/5/jobStartedOn": "8-2009", "experiences/5/jobStillWorking": "false", "experiences/5/title": "Hotel Manager", "experiences/6/companyName": "Assistant Manager & Guest Relations Executive The Seasons Hotel Full-time", "experiences/6/employmentType": "Full-time", "experiences/6/jobDescription": "Directly supervised Front Office operations, ensuring a high standard of guest service while maintaining property profitability. I balanced administrative leadership with hands-on guest relations to drive occupancy and service excellence.\n\nKey Responsibilities & Achievements: * Front Office Leadership: Supervised daily desk activities, conducted shift briefings, and led staff meetings to ensure seamless communication and 100% operational readiness.\n\nOccupancy Optimization: Performed daily house counts and arrival reviews, proactively identifying potential rooming issues and directing the team to achieve 100% occupancy goals.\n\nFinancial Alignment: Managed department operations with a clear focus on the property’s overall financial goals, ensuring high service standards were met within profitable margins.\n\nGuest Experience & Crisis Resolution: Acted as the primary point of contact for guest queries and complaints, taking personal responsibility for rapid service recovery and guest satisfaction.\n\nStaff Coaching: Improved overall service quality by providing individual coaching to staff members, helping them better understand and anticipate guest needs.\n\nVIP Management: As Guest Relations Executive, ensured all VIPs and long-stay guests received personalized attention, enhancing the hotel's reputation for high-touch service.", "experiences/6/jobEndedOn": "8-2009", "experiences/6/jobLocation": "Pattaya, Chon Buri, Thailand", "experiences/6/jobStartedOn": "4-2008", "experiences/6/jobStillWorking": "false", "experiences/6/title": "Assistant Manager & Guest Relations Executive The Seasons Hotel Full-time", "experiences/7/companyName": "H.B. Hotel India Full-time | Oct 2004 – Jan 2006 (1 yr 4 mos) India", "experiences/7/jobDescription": "Completed a comprehensive Management Training program, rotating through all core hotel departments to build a foundational understanding of full-scale property operations. This period was critical in developing the cross-functional expertise required for senior hospitality leadership.\n\nKey Rotations & Learning Milestones:\n\nFront Office & Guest Relations: Gained proficiency in front desk operations, reservations, and concierge services, focusing on providing high-quality property and local city information to international guests.\n\nF&B & Restaurant Management: Trained in restaurant service processes, floor management, and the coordination between front-of-house and back-of-house.\n\nCulinary & Kitchen Operations: Acquired hands-on experience in kitchen workflow, food safety, and operational efficiency within a high-pressure environment.\n\nHousekeeping & Rooms Division: Developed an eye for detail regarding property standards, room inspections, and the logistics of housekeeping management.\n\nLeadership Foundation: Successfully demonstrated increasing proficiency in managerial responsibilities, learning to lead small teams and manage departmental tasks.", "experiences/7/jobEndedOn": "1-2006", "experiences/7/jobLocation": "Chandigarh, India", "experiences/7/jobStartedOn": "10-2004", "experiences/7/jobStillWorking": "false", "experiences/7/title": "Management Trainee", "experiencesCount": "8", "firstName": "Rahul", "firstRoleYear": "2004", "followers": "13122", "fullName": "Rahul G.", "headline": "Hotel General Manager | Driving Exceptional Guest Experiences and Profitability", "isCreator": "false", "isCurrentlyEmployed": "true", "isInfluencer": "false", "isJobSeeker": "false", "isPremium": "false", "isRetired": "false", "isVerified": "false", "jobLocation": "Pattaya, Thailand, South East Asia", "jobStartedOn": "4-2019", "jobStillWorking": "true", "jobTitle": "\"General Manager at Mind Resort Pattaya | Hospitality Leader | Revenue & Guest Experience Expert\"", "languages/0/name": "English", "languages/1/name": "Hindi", "lastName": "G.", "licenseAndCertificates/0/authority": "Google", "licenseAndCertificates/0/name": "Foundations of Digital Marketing and E-commerce", "licenseAndCertificates/0/startedOn/month": "6", "licenseAndCer